  pairing_logic = '{"pairs_well_before":["Coach Point-and-Go Drill","Color Cone Call-Out","Output acceleration block"],"pairs_well_after":["Two-Point Start Walk-In","Falling Start Position Hold","Arm Action Drill"],"good_for_sessions":["general_warmup","sprint_prep","landing_prep"],"avoid_before":["Max acceleration if athlete guesses or false-steps","High-speed reactive races if deceleration is poor"],"avoid_after":[],"do_not_use_when":["No safe run-out","Athlete cannot stop safely","Crowded group layout","Cue system is unclear"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["NSCA reaction drills for visual cueing and first-step quickness"],"internal_notes":["Final Skill / Movement Intelligence card — bridge to Output acceleration."]}'::jsonb,
  updated_at = now()
WHERE slug = 'gate-reaction-drill';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'reactive_start',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = TRUE,
  fatigue_sensitivity = 5,
  fatigue_cost = 3,
  technical_complexity = 5,
  impact_level = 1,
  intensity_ceiling = 'high',
  notes = 'If athletes sprint maximally through gates with full recovery, classify as Output. Skill version emphasizes cue-read and first step.'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'skill_movement_intelligence'
JOIN coaching.phase_order_slot pos ON pos.key = 'reactive_start' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'gate-reaction-drill';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'reps',
  default_sets = 2,
  default_reps = 4,
  default_distance = NULL,
  default_work_seconds = NULL,
  default_rest_seconds = 30,
  est_seconds_per_set = 45,
  default_rpe_min = 3,
  default_rpe_max = 6,
  session_volume_min = 3,
  session_volume_max = 10
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'gate-reaction-drill';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = CASE WHEN FALSE THEN 7 ELSE r.weekly_max_frequency END
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'gate-reaction-drill';

