UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('mirror-shuffle-drill', 'Narrow lane, walking mirror, no fakes.', 'No default sex-based adjustment. Scale by reaction skill, lateral mechanics, stopping control, pairing, and confidence.'),
  ('coach-point-and-go', 'Two directions only: left/right step.', 'No default sex-based adjustment. Scale by reaction skill, lateral mechanics, stopping control, pairing, and confidence.'),
  ('colored-cone-call-out', 'Two colors only; step or jog to cone.', 'No default sex-based adjustment. Scale by reaction skill, lateral mechanics, stopping control, pairing, and confidence.'),
  ('ball-drop-reaction', 'Short distance, allow one or two bounces.', 'No default sex-based adjustment. Scale by reaction skill, lateral mechanics, stopping control, pairing, and confidence.'),
  ('partner-shadow-tag', 'Shadow only, no tagging, walking or slow shuffle.', 'No default sex-based adjustment. Scale by reaction skill, lateral mechanics, stopping control, pairing, and confidence.'),
  ('gate-reaction-drill', 'Two gates only; step or jog through gate.', 'No default sex-based adjustment. Scale by reaction skill, lateral mechanics, stopping control, pairing, and confidence.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

