-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('mirror-shuffle-drill', 'The mirror drill adds perception-action to lateral movement — the athlete watches a partner, interprets direction changes, and matches movement while preserving base, posture, and foot spacing.', 'Belongs in Perception-Action / Reactive Movement (mirror_reaction). Competitive max-speed mirror work moves toward Output or sport-specific agility.', 'After lateral shuffle mechanics when athletes need partner tracking before reactive defensive work.', 'Do not exceed ~15s rounds in Skill or skip lateral shuffle prerequisites. Collisions and feet clicking together mean regress speed or lane width.', 'Scale by lane width, round length, and leader speed; pair by size and control.'),
  ('coach-point-and-go', 'Introduces a simple visual cue: observe, identify direction, and execute. NSCA reaction-drill guidance uses visual signals for reactive quickness and cue processing.', 'Belongs in Perception-Action / Reactive Movement (visual_reaction). Sprint-out versions belong in Output.', 'Early reactive block before color call-outs or gate reactions when athletes need simple visual decisions.', 'Do not add more than 2–4 directions for beginners or turn into repeated shuttle conditioning.', 'Start with two directions; add complexity only when first-step and stop quality are clean.'),
  ('colored-cone-call-out', 'Color call-outs add a decision layer — identify the cue, select the target, and move with mechanics. Entry-level perception-action, not advanced game vision.', 'Belongs in Perception-Action / Reactive Movement (visual_decision). Long cone-call circuits become conditioning.', 'After point-and-go when athletes need color discrimination before gate or ball reactions.', 'Do not use too many colors too soon or turn into shuttle conditioning without decision quality.', 'Use visually distinguishable cones; reduce colors and distance before adding speed.'),
  ('ball-drop-reaction', 'Gives a clear external cue the athlete cannot fully predict — track, react, accelerate, and coordinate the catch. NSCA and JASC ball-drop setups support reactive quickness training.', 'Belongs in Perception-Action / Reactive Movement (object_reaction). Max sprint-and-catch with full rest belongs in Output.', 'After gate or point-and-go when athletes need object tracking before Output acceleration.', 'Do not allow diving in Skill, use distance too far for level, or repeat as max-acceleration conditioning.', 'Short distance first; allow extra bounces for beginners; require safe deceleration after catch.'),
  ('partner-shadow-tag', 'Trains perception-action in a game-like environment — read another person, use space, manage boundaries, evade, pursue, stop, and restart. Closer to sport movement than pre-planned patterns.', 'Belongs in Perception-Action / Reactive Movement (movement_game). Can drift into Fitness quickly — keep rounds short.', 'After mirror shuffle or point-and-go when athletes need live opponent information in a bounded game.', 'Rounds over ~12s, unsafe contact, or mismatched pairs turn this into conditioning chaos, not Skill.', 'Pair by size and speed; use shadow-only for beginners; stop on whistle immediately.'),
  ('gate-reaction-drill', 'Combines start, visual decision, and spatial target — identify which gate is available, choose the path, and initiate clean acceleration. Strong Skill-to-Output bridge with a decision component.', 'Belongs in Perception-Action / Reactive Movement (reactive_start). Max sprint through gates with full recovery belongs in Output.', 'Late in Skill block before Output acceleration when athletes can read cues and decelerate after gates.', 'Timed competitive sprints, crossing athlete paths, or unclear cues move this out of Skill intent.', 'Two gates for beginners; require safe run-out and deceleration past each gate.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Perception-cluster validation education (completes 50-card Skill library)
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'skill_perception_readiness',
  NULL,
  'Perception-Action / Reactive Movement without chaos',
  'Reactive drills should sharpen see-decide-move quality at low-to-moderate intensity — not become conditioning games, max sprints, or unsafe partner contact in Skill.',
  'Perception cluster cards teach partner mirroring, coach visual cues, color decisions, ball drops, bounded tag games, and gate reactions while athletes are fresh.',
  'Reactive skill under fatigue or poor spacing transfers into guessing, collisions, and sloppy first steps. Skill teaches perception-action; Output expresses it fast; Fitness repeats it under load.',
  'Keep mirror/tag rounds ≤12–15s, require lateral shuffle prep before mirror work, cap ball/gate reps with full rest, use no-contact shadow for beginners, and move timed max sprints to Output.',
  'Do not assign reactive work after HIIT, allow diving in ball drop, run long tag rounds, use crossing gate layouts, or skip deceleration prerequisites — reduce dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
